          )

          for await (const chunk of streamGenerator) {
            fullContent += chunk
            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'chunk', content: chunk })}\n\n`))
          }

          // 4. Валидация качества перед сохранением
